          </div>
          <span className="font-bold text-xl tracking-tighter text-slate-900">
            Ally<span className="text-blue-600">.</span>Partners
          </span>
        </a>

        <div className="hidden md:flex items-center gap-10">
          <div className="flex gap-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className="text-[13px] uppercase tracking-widest font-semibold text-slate-500 hover:text-blue-600 transition-colors"
              >
                {link.name}
